"use client";

import { useRouter } from "next/navigation";
import { useState, useEffect } from "react";
import API from "@/app/lib/api";

export default function Home() {
  const router = useRouter();
  const [active, setActive] = useState<string | null>(null);
  const [tests, setTests] = useState<any[]>([]);

  useEffect(() => {
    const fetchTests = async () => {
      const { data } = await API.get("/tests");
      setTests(data);
    };
    fetchTests();
  }, []);

  const handleTestClick = async (id: string) => {
    try {
      await API.get("/user/profile");
      router.push(`/quiz/${id}`);
    } catch {
      router.push("/register");
    }
  };

  return (
    <div>

      {/* HOME */}
      <section id="home" className="h-screen flex items-center justify-center bg-blue-500 text-white">
        <button onClick={() => router.push("/register")} className="bg-white text-blue-600 px-6 py-2 rounded">
          Start Free Now
        </button>
      </section>

      {/* TESTS */}
      <section id="tests" className="py-20 px-6">
        <h2 className="text-3xl font-bold text-center mb-10">Tests</h2>

        <div className="max-w-3xl mx-auto">

          <div className="border p-4 cursor-pointer" onClick={() => setActive("tests")}>
            📁 Available Tests
          </div>

          {active === "tests" && (
            <div className="mt-4 space-y-2">
              {tests.map((t) => (
                <div
                  key={t._id}
                  onClick={() => handleTestClick(t._id)}
                  className="border p-3 cursor-pointer"
                >
                  {t.title}
                </div>
              ))}
            </div>
          )}

        </div>
      </section>

    </div>
  );
}